create table CREDIT_CARD_TXN
(
    CREDIT_CARD_TXN_ID uuid                                  not null
        primary key,
    ACCOUNT_ID         uuid                                  not null,
    DETAILS            text                                  not null,
    AMOUNT             double                                not null,
    DATE               text                                  not null,
    TRANSACTION_SOURCE text                                  not null,
    MERCHANT_ID        uuid                                  null,
    RECEIVABLE         tinyint(1)                            null,
    DEBTOR_ID          uuid                                  null,
    DAY                int                                   null,
    DAY_OF_WEEK        text                                  null,
    WEEK               int                                   null,
    MONTH              int                                   null,
    MONTH_NAME         text                                  null,
    YEAR               int                                   null,
    CREATED            timestamp default current_timestamp() null
);

